39	    type FixFormat_t is record
40	        S   : natural range 0 to 1;  -- Sign bit.
41	        I   : integer;               -- Integer bits.
42	        F   : integer;               -- Fractional bits.
43	    end record;
44	    
45	    constant NullFixFormat_c    : FixFormat_t := (0, 0, -1);
46	    
47	    type FixFormatArray_t is array(natural range <>) of FixFormat_t;
48	    
49	    type FixRound_t is
50	    (
51	        Trunc_s,        -- Truncation (no rounding).
52	        NonSymPos_s,    -- Non-symmetric positive (half-up).
53	        NonSymNeg_s,    -- Non-symmetric negative (half-down).
54	        SymInf_s,       -- Symmetric towards +/- infinity.
55	        SymZero_s,      -- Symmetric towards 0.
56	        ConvEven_s,     -- Convergent towards even number.
57	        ConvOdd_s       -- Convergent towards odd number.
58	    );
59	    
60	    type FixSaturate_t is
61	    (
62	        None_s,         -- No saturation, no warning.
63	        Warn_s,         -- No saturation, only warning.
64	        Sat_s,          -- Only saturation, no warning.
65	        SatWarn_s       -- Saturation and warning.
66	    );
67	    
68	    type RegisterMode_t is
69	    (
70	        Auto_s,         -- Inserts the recommended registering. See cl_fix_recommended_pipelining.
71	        Yes_s,          -- Inserts all registering. Can be useful for consistent latency.
72	        No_s            -- Inserts no registering. Use with caution (poor timing performance).
73	    );
