268	---------------------------------------------------------------------------------------------------
269	-- Package Body
270	---------------------------------------------------------------------------------------------------
271	package body en_cl_fix_pkg is
272	    
273	    -----------------------------------------------------------------------------------------------
274	    -- Internal Functions
275	    -----------------------------------------------------------------------------------------------
276	    function max_real(fmt : FixFormat_t) return real is
277	    begin
278	        return 2.0**fmt.I - 2.0**(-fmt.F);
279	    end function;
280	    
281	    function min_real(fmt : FixFormat_t) return real is
282	    begin
283	        if fmt.S = 1 then
284	            return -2.0**fmt.I;
285	        else
286	            return 0.0;
287	        end if;
288	    end function;
289	    
290	    function get_half(aFmt, rFmt : FixFormat_t) return unsigned is
291	        constant tie_c  : natural := aFmt.F - rFmt.F - 1;
292	        variable v      : unsigned(cl_fix_width(aFmt)-1 downto 0) := (others => '0');
293	    begin
294	        -- Set the "tie" bit (i.e. half the LSB weight of rFmt)
295	        v(tie_c) := '1';
296	        return v;
297	    end function;
298	    
299	    function get_unit_bit(a : std_logic_vector; aFmt, rFmt : FixFormat_t) return std_logic is
300	        -- Force downto 0
301	        constant a_c    : std_logic_vector(a'length-1 downto 0) := a;
302	        constant unit_c : natural := aFmt.F - rFmt.F;
303	    begin
304	        if unit_c >= cl_fix_width(aFmt) then
305	            -- Implicit MSB extension
306	            return cl_fix_sign(a_c, aFmt);
307	        else
308	            -- Normal behavior: get the explicit "unit" bit (i.e. the LSB weight of rFmt)
309	            return a_c(unit_c);
310	        end if;
311	    end function;
312	    
313	    function resize_sensible(a : signed; n : natural) return signed is
314	        -- Force downto 0
315	        constant a_c    : signed(a'length-1 downto 0) := a;
316	        variable v      : signed(n-1 downto 0);
317	    begin
318	        if n >= a'length then
319	            -- Sign extension: Use the standard VHDL function.
320	            v := resize(a_c, n);
321	        else
322	            -- Truncation: Just do plain truncation.
323	            -- This is usually more sensible than numeric_std.resize, which preserves the sign bit.
324	            v := a_c(n-1 downto 0);
325	        end if;
326	        return v;
327	    end function;
328	    
329	    function convert(a : std_logic_vector; aFmt, rFmt : FixFormat_t) return std_logic_vector is
330	        -- Force downto 0
331	        constant a_c    : std_logic_vector(cl_fix_width(aFmt)-1 downto 0) := a;
332	        
333	        -- This function converts from aFmt to rFmt without any rounding or saturation:
334	        --     - It does *not* support rFmt.F < aFmt.F (offset_c is type natural). To reduce frac
335	        --       bits, always use cl_fix_round (Trunc_s rounding mode can be used to truncate).
336	        --     - It does support (rFmt.S+rFmt.I) < (aFmt.S+aFmt.I) *without* saturation. In other
337	        --       words, this implements cl_fix_saturate, with None_s saturation mode.
338	        constant r_width_c  : natural := cl_fix_width(rFmt);
339	        constant offset_c   : natural := rFmt.F - aFmt.F;
340	        variable result_v   : std_logic_vector(r_width_c-1 downto 0) := (others => '0');
341	    begin
342	        -- Write the input value into result_v with correct binary point alignment.
343	        -- We sign extend into any extra int bits (and offset_c LSBs are defaulted to '0').
344	        if aFmt.S = 0 then
345	            result_v(r_width_c-1 downto offset_c) := std_logic_vector(resize(unsigned(a_c), r_width_c - offset_c));
346	        else
347	            result_v(r_width_c-1 downto offset_c) := std_logic_vector(resize_sensible(signed(a_c), r_width_c - offset_c));
348	        end if;
349	        
350	        return result_v;
351	    end function;
352	    
353	    function union(aFmt, bFmt : FixFormat_t) return FixFormat_t is
354	    begin
355	        return (
356	            S => maximum(aFmt.S, bFmt.S),
357	            I => maximum(aFmt.I, bFmt.I),
358	            F => maximum(aFmt.F, bFmt.F)
359	        );
360	    end function;
361	    
362	    -----------------------------------------------------------------------------------------------
363	    -- Public Functions
364	    -----------------------------------------------------------------------------------------------
365	    function cl_fix_width(fmt : FixFormat_t) return natural is
366	    begin
367	        return fmt.S + fmt.I + fmt.F;
368	    end;
369	    
370	    function cl_fix_max_value(fmt : FixFormat_t) return std_logic_vector is
371	        variable result_v : std_logic_vector(cl_fix_width(fmt)-1 downto 0);
372	    begin
373	        result_v := (others => '1');
374	        if fmt.S = 1 then
375	            result_v(result_v'high) := '0';
376	        end if;
377	        return result_v;
378	    end;
379	    
380	    function cl_fix_min_value(fmt : FixFormat_t) return std_logic_vector is
381	        variable result_v : std_logic_vector(cl_fix_width(fmt)-1 downto 0);
382	    begin
383	        if fmt.S = 1 then
384	            result_v := (others => '0');
385	            result_v(result_v'left) := '1';
386	        else
387	            result_v := (others => '0');
388	        end if;
389	        return result_v;
390	    end;
391	    
392	    function cl_fix_add_fmt(a_fmt : FixFormat_t; b_fmt : FixFormat_t) return FixFormat_t is
393	        -- We must consider both extremes:
394	        
395	        -- rmax = amax+bmax
396	        --      = (2**aFmt.I - 2**-aFmt.F) + (2**bFmt.I - 2**-bFmt.F)
397	        -- If aFmt.I >= bFmt.I, then we get 1 bit of growth if:
398	        --           -2**-aFmt.F + 2**bFmt.I - 2**-bFmt.F >= 0
399	        -- If bFmt.I >= aFmt.I, then we get 1 bit of growth if:
400	        --           -2**-bFmt.F + 2**aFmt.I - 2**-aFmt.F >= 0
401	        -- Note that the aFmt.I == bFmt.I case is covered by either condition.
402	        -- We define maxFmt as the format with most int bits, and minFmt as the other. (As noted
403	        -- above, it doesn't matter which we treat as max/min when aFmt.I == bFmt.I). This gives a
404	        -- general expression for when bit-growth happens:
405	        --           -2**-maxFmt.F + 2**minFmt.I - 2**-minFmt.F >= 0
406	        -- If we rearrange the expression into pure integer arithmetic, we get:
407	        --      2**(minFmt.F+minFmt.I+maxFmt.F) >= 2**minFmt.F + 2**maxFmt.F
408	        -- Equality is only possible if the RHS is a power of 2, so we can remove the 2**n by
409	        -- splitting this into two simple cases:
410	        --      (1) If minFmt.F == maxFmt.F = F:
411	        --          F+minFmt.I+F >= F+1
412	        --          minFmt.I+F >= 1
413	        --          minFmt.I+F > 0
414	        --      (2) Else:
415	        --          minFmt.F+minFmt.I+maxFmt.F > max(minFmt.F, maxFmt.F)
416	        --          minFmt.I+maxFmt.F > max(minFmt.F, maxFmt.F) - minFmt.F
417	        -- Clearly, the expression for (2) also covers (1). We finally simplify the expression by
418	        -- noting that in general x+y-max(x,y) = min(x,y):
419	        --          minFmt.I + min(minFmt.F, maxFmt.F) > 0
420	        --          min(aFmt.I, bFmt.I) + min(aFmt.F, bFmt.F) > 0
421	        -- There is probably a more direct way to derive this simple expression.
422	        constant rmax_growth_c  : natural := choose(minimum(a_fmt.I, b_fmt.I) + minimum(a_fmt.F, b_fmt.F) > 0, 1, 0);
423	        
424	        -- rmin = amin+bmin
425	        --     If aFmt.S = 0 and bFmt.S = 0: 0 + 0
426	        --     If aFmt.S = 0 and bFmt.S = 1: 0 + -2**bFmt.I
427	        --     If aFmt.S = 1 and bFmt.S = 0: -2**aFmt.I + 0
428	        --     If aFmt.S = 1 and bFmt.S = 1: -2**aFmt.I + -2**bFmt.I
429	        constant rmin_growth_c  : natural := choose(a_fmt.S = 1 and b_fmt.S = 1, 1, 0);
430	    begin
431	        return (
432	            maximum(a_fmt.S, b_fmt.S),
433	            maximum(a_fmt.I, b_fmt.I) + maximum(rmin_growth_c, rmax_growth_c),
434	            maximum(a_fmt.F, b_fmt.F)
435	        );
436	    end;
437	    
438	    function cl_fix_sub_fmt(a_fmt : FixFormat_t; b_fmt : FixFormat_t) return FixFormat_t is
439	        variable growth_v       : natural range 0 to 1;
440	        variable rmaxI_v        : integer;
441	        variable rminI_v        : integer;
442	        variable S_v            : natural range 0 to 1;
443	        variable I_v            : integer;
444	    begin
445	        -- We must consider both extremes:
446	        
447	        -- rmax = amax-bmin
448	        --     If bFmt.S = 0: rmax = (2**aFmt.I - 2**-aFmt.F) - 0
449	        --     If bFmt.S = 1: rmax = (2**aFmt.I - 2**-aFmt.F) + 2**bFmt.I
450	        -- If bFmt.S = 0, then rmaxFmt = aFmt.
451	        -- If bFmt.S = 1 and aFmt.I >= bFmt.I, then we get 1 bit of growth if:
452	        --                -2**-aFmt.F + 2**bFmt.I >= 0
453	        --                              2**bFmt.I >= 2**-aFmt.F
454	        -- If bFmt.S = 1 and bFmt.I >= aFmt.I, then we get 1 bit of growth if:
455	        --                -2**-aFmt.F + 2**aFmt.I >= 0
456	        --                              2**aFmt.I >= 2**-aFmt.F
457	        if b_fmt.S = 0 then
458	            rmaxI_v := a_fmt.I;
459	        else
460	            growth_v := choose(minimum(a_fmt.I, b_fmt.I) >= -a_fmt.F, b_fmt.S, 0);
461	            rmaxI_v := maximum(a_fmt.I, b_fmt.I) + growth_v;
462	        end if;
463	        
464	        -- rmin = amin-bmax
465	        --     If aFmt.S = 0: rmin = 0 - (2**bFmt.I - 2**-bFmt.F)
466	        --     If aFmt.S = 1: rmin = -2**aFmt.I - (2**bFmt.I - 2**-bFmt.F)
467	        -- If aFmt.S = 0 and bFmt.I = -bFmt.F, then rFmt.S=0 with no requirement on rFmt.I.
468	        -- If aFmt.S = 0 and bFmt.I = -bFmt.F+1, then we have a special case (power of 2) such that
469	        -- rmin = -2**-bFmt.F, so rFmt.S=1 and rFmt.I = -bFmt.F.
470	        -- If aFmt.S = 0 and (all other cases), then rFmt.S=1 and rFmt.I=bFmt.I.
471	        -- If aFmt.S = 1 and aFmt.I >= bFmt.I, then we get 1 bit of growth if:
472	        --                       2**bFmt.I - 2**-bFmt.F > 0
473	        -- If aFmt.S = 1 and bFmt.I >= aFmt.I, then we get 1 bit of growth if:
474	        --                       2**aFmt.I - 2**-bFmt.F > 0
475	        if a_fmt.S = 0 then
476	            if cl_fix_width(b_fmt) = 1 and b_fmt.S = 1 then
477	                -- Special case: a is unsigned and b is 1-bit signed:
478	                S_v := 0;
479	                I_v := rmaxI_v;
480	            elsif b_fmt.I = -b_fmt.F+1 then
481	                -- Special case: a is unsigned and rmin is a power of 2
482	                S_v := 1;
483	                I_v := maximum(rmaxI_v, -b_fmt.F);
484	            else
485	                -- Normal case for unsigned a
486	                S_v := 1;
487	                I_v := maximum(rmaxI_v, b_fmt.I);
488	            end if;
489	        else
490	            -- Signed a
491	            S_v := 1;
492	            growth_v := choose(minimum(a_fmt.I, b_fmt.I) > -b_fmt.F, a_fmt.S, 0);
493	            rminI_v := maximum(a_fmt.I, b_fmt.I) + growth_v;
494	            I_v := maximum(rmaxI_v, rminI_v);
495	        end if;
496	        
497	        return (S_v, I_v, maximum(a_fmt.F, b_fmt.F));
498	    end;
499	    
500	    function cl_fix_addsub_fmt(a_fmt : FixFormat_t; b_fmt : FixFormat_t) return FixFormat_t is
501	        constant add_fmt_c  : FixFormat_t := cl_fix_add_fmt(a_fmt, b_fmt);
502	        constant sub_fmt_c  : FixFormat_t := cl_fix_sub_fmt(a_fmt, b_fmt);
503	    begin
504	        -- Take the max over add and sub formats.
505	        return union(add_fmt_c, sub_fmt_c);
506	    end;
507	    
508	    function cl_fix_mult_fmt(a_fmt : FixFormat_t; b_fmt : FixFormat_t) return FixFormat_t is
509	        constant a_neg_fmt_c    : FixFormat_t := cl_fix_neg_fmt(a_fmt);
510	        constant b_neg_fmt_c    : FixFormat_t := cl_fix_neg_fmt(b_fmt);
511	        variable rmaxI_v        : integer;
512	        variable S_v            : natural range 0 to 1;
513	        variable I_v            : integer;
514	    begin
515	        -- We must consider both extremes:
516	        
517	        -- rmax:
518	        -- If aFmt.S == 1 and bFmt.S == 1, then:
519	        --     rmax = amin * bmin
520	        --          = -2**aFmt.I * -2**bFmt.I = 2**(aFmt.I + bFmt.I)
521	        --          ==> aFmt.I + bFmt.I + 1 int bits.
522	        -- Else:
523	        --     rmax = amax * bmax
524	        --          = (2**aFmt.I - 2**-aFmt.F) * (2**bFmt.I - 2**-bFmt.F)
525	        --          = 2**(aFmt.I + bFmt.I) - 2**(aFmt.I - bFmt.F) - 2**(bFmt.I - aFmt.F) + 2**(-aFmt.F - bFmt.F)
526	        --     This will typically need aFmt.I + bFmt.I int bits, but -1 bit if:
527	        --          2**(aFmt.I + bFmt.I) - 2**(aFmt.I - bFmt.F) - 2**(bFmt.I - aFmt.F) + 2**(-aFmt.F - bFmt.F) < 2**(aFmt.I + bFmt.I - 1)
528	        --     If we define x=aFmt.I+aFmt.F and y=bFmt.I+bFmt.F, then we can rearrange this to:
529	        --          2**(x+y-1) + 1 < 2**x + 2**y
530	        --     Further rearrangement leads to:
531	        --          (2**x - 2)(2**y - 2) < 2
532	        --     Note that x>=0 and y>=0 because we do not support I+F<0. So, it is fairly easy to see
533	        --     the inequality is true iff x<=1 or y<=1 (and this is trivial to confirm numerically).
534	        if a_fmt.S = 1 and b_fmt.S = 1 then
535	            rmaxI_v := a_fmt.I + b_fmt.I + 1;
536	        elsif a_fmt.I+a_fmt.F <= 1 or b_fmt.I+b_fmt.F <= 1 then
537	            rmaxI_v := a_fmt.I + b_fmt.I - 1;
538	        else
539	            rmaxI_v := a_fmt.I + b_fmt.I;
540	        end if;
541	        
542	        -- rmin:
543	        -- If aFmt.S == 0 and bFmt.S == 0, then:
544	        --     rmin = amin * bmin = 0
545	        --     ==> No requirement.
546	        -- If aFmt.S == 0 and bFmt.S == 1, then:
547	        --     rmin = amax * bmin = (2**aFmt.I - 2**-aFmt.F) * -2**bFmt.I
548	        --                        = -amax * 2**bFmt.I
549	        --     ==> Same as FixFormat.ForNeg(aFmt).I + bFmt.I
550	        -- If aFmt.S == 1 and bFmt.S == 0, then:
551	        --     rmin = amin * bmax
552	        --     ==> Same as FixFormat.ForNeg(bFmt).I + aFmt.I
553	        -- If aFmt.S == 1 and bFmt.S == 1, then:
554	        --     rmin = min(amax * bmin, amin * bmax)
555	        --     ==> Never exceeds rmaxI ==> Ignore.
556	        
557	        -- The requirement can exceed rmaxI only if aFmt.S != bFmt.S and we don't run into the same
558	        -- special case as FixFormat.ForNeg() (i.e. the unsigned value being 1-bit).
559	        if a_fmt.S = 0 and b_fmt.S = 1 then
560	            I_v := maximum(rmaxI_v, a_neg_fmt_c.I + b_fmt.I);
561	        elsif a_fmt.S = 1 and b_fmt.S = 0 then
562	            I_v := maximum(rmaxI_v, a_fmt.I + b_neg_fmt_c.I);
563	        else
564	            I_v := rmaxI_v;
565	        end if;
566	        
567	        -- Sign bit
568	        if cl_fix_width(a_fmt) = 1 and a_fmt.S = 1 and cl_fix_width(b_fmt) = 1 and b_fmt.S = 1 then
569	            -- Special case: 1-bit signed * 1-bit signed is unsigned
570	            S_v := 0;
571	        else
572	            -- Normal: If either input is signed, then output is signed
573	            S_v := maximum(a_fmt.S, b_fmt.S);
574	        end if;
575	        
576	        return (S_v, I_v, a_fmt.F+b_fmt.F);
577	    end;
578	    
579	    function cl_fix_neg_fmt(a_fmt : FixFormat_t) return FixFormat_t is
580	    begin
581	        -- 1-bit unsigned inputs are special (neg is 1-bit signed)
582	        if a_fmt.S = 0 and cl_fix_width(a_fmt) = 1 then
583	            return (1, a_fmt.I + a_fmt.S - 1, a_fmt.F);
584	        end if;
585	        
586	        -- Normal case: 1 bit of growth for signed inputs due to the asymmetry of two's complement.
587	        return (1, a_fmt.I + a_fmt.S, a_fmt.F);
588	    end;
