590	    function cl_fix_abs_fmt(a_fmt : FixFormat_t) return FixFormat_t is
591	        constant neg_fmt_c  : FixFormat_t := cl_fix_neg_fmt(a_fmt);
592	    begin
593	        return union(a_fmt, neg_fmt_c);
594	    end;
