608	    function cl_fix_round_fmt(a_fmt : FixFormat_t; r_frac_bits : integer; rnd : FixRound_t) return FixFormat_t is
609	        variable I_v    : integer;
610	    begin
611	        if r_frac_bits >= a_fmt.F then
612	            -- If fractional bits are not being reduced, then nothing happens to int bits.
613	            I_v := a_fmt.I;
614	        elsif rnd = Trunc_s then
615	            -- Crude truncation has no effect on int bits.
616	            I_v := a_fmt.I;
617	        else
618	            -- All other rounding modes can overflow into +1 int bit.
619	            I_v := a_fmt.I + 1;
620	        end if;
621	        
622	        -- Force result to be at least 1 bit wide
623	        if a_fmt.S + I_v + r_frac_bits < 1 then
624	            I_v := -a_fmt.S - r_frac_bits + 1;
625	        end if;
626	        
627	        return (a_fmt.S, I_v, r_frac_bits);
628	    end;
