638	    function to_string(a : std_logic_vector; a_fmt : FixFormat_t) return string is
639	        function to_char(x : std_logic) return character is
640	            constant slv_char_c : string(1 to 9) := ('U', 'X', '0', '1', 'Z', 'W', 'L', 'H', '-');
641	        begin
642	            return slv_char_c(1 + std_logic'pos(x));
643	        end;
644	        
645	        -- Force downto 0
646	        constant a_c            : std_logic_vector(cl_fix_width(a_fmt)-1 downto 0) := a;
647	        constant all_explicit_c : natural := choose(a_fmt.S+a_fmt.I>=0 and a_fmt.F>=0, 1, 0);
648	        constant pre_length_c   : natural := choose(a_fmt.S+a_fmt.I<0, 3-(a_fmt.S+a_fmt.I), 0);
649	        constant post_length_c  : natural := choose(a_fmt.F<0, 3-a_fmt.F, 0);
650	        variable pre_v          : string(1 to pre_length_c);
651	        variable main_v         : string(1 to a_c'length+all_explicit_c); -- +1 for binary point.
652	        variable post_v         : string(1 to post_length_c);
653	    begin
654	        if all_explicit_c = 1 then
655	            -- Print explicit S+I bits
656	            for i in 1 to a_fmt.S+a_fmt.I loop
657	                main_v(i) := to_char(a_c(a_c'length-i));
658	            end loop;
659	            
660	            -- Print binary point
661	            main_v(a_fmt.S+a_fmt.I+1) := '.';
662	            
663	            -- Print explicit F bits
664	            for i in 1 to a_fmt.F loop
665	                main_v(a_fmt.S+a_fmt.I+1+i) := to_char(a_c(a_fmt.F-i));
666	            end loop;
667	        else
668	            -- Print implicit leading fractional bits (if a_fmt.S+a_fmt.I < 0)
669	            if pre_length_c > 0 then
670	                pre_v(1 to 2) := ".(";
671	                for i in 3 to pre_length_c-1 loop
672	                    pre_v(i) := to_char(cl_fix_sign(a, a_fmt));
673	                end loop;
674	                pre_v(pre_length_c) := ')';
675	            end if;
676	            
677	            -- Print all explicit bits
678	            for i in 1 to a_c'length loop
679	                main_v(i) := to_char(a_c(a_c'length-i));
680	            end loop;
681	            
682	            -- Print implicit trailing integer bits (if a_fmt.F < 0)
683	            if post_length_c > 0 then
684	                post_v(1) := '(';
685	                for i in 2 to post_length_c-2 loop
686	                    post_v(i) := '0';
687	                end loop;
688	                post_v(post_length_c-1 to post_length_c) := ").";
689	            end if;
690	        end if;
691	        
692	        return pre_v & main_v & post_v;
693	    end;
