729	    function cl_fix_format_from_string(Str : string) return FixFormat_t is
730	        variable Format_v   : FixFormat_t;
731	        variable Index_v    : integer;
732	    begin
733	        -- Parse Format
734	        Index_v := Str'low;
735	        Index_v := string_find_next_match(Str, '(', Index_v);
736	        assert Index_v > 0
737	            report "cl_fix_format_from_string: Format string is missing '('" severity Failure;
738	        -- Number of sign bits must be 0 or 1
739	        if Str(Index_v+1) = '0' then
740	            Format_v.S := 0;
741	        elsif Str(Index_v+1) = '1' then
742	            Format_v.S := 1;
743	        else
744	            report "cl_fix_format_from_string: Unsupported number of sign bits: " & Str(Index_v+1) severity Failure;
745	        end if;
746	        Index_v := string_find_next_match(Str, ',', Index_v+1);
747	        assert Index_v > 0
748	            report "cl_fix_format_from_string: Format string is missing ',' between S and I" severity Failure;
749	        Format_v.I := string_parse_int(Str, Index_v+1);
750	        Index_v := string_find_next_match(Str, ',', Index_v+1);
751	        assert Index_v > 0
752	            report "cl_fix_format_from_string: Format string is missing ',' between I and F" severity Failure;
753	        Format_v.F := string_parse_int(Str, Index_v+1);
754	        Index_v := string_find_next_match(Str, ')', Index_v+1);
755	        assert Index_v > 0
756	            report "cl_fix_format_from_string: Format string is missing ')'" severity Failure;
757	        return Format_v;
758	    end;
