910	    function cl_fix_round(
911	        a           : std_logic_vector;
912	        a_fmt       : FixFormat_t;
913	        result_fmt  : FixFormat_t;
914	        round       : FixRound_t := Trunc_s;
915	        fmt_check   : boolean := true
916	    ) return std_logic_vector is
917	        -- Force downto 0
918	        constant a_c            : std_logic_vector(cl_fix_width(a_fmt)-1 downto 0) := a;
919	        
920	        -- The result format takes care of potential integer growth due to the rounding mode.
921	        -- In the intermediate calculation, we need to +/- up to 2.0**-(result_fmt.F+1) in order to
922	        -- implement each rounding algorithm (except trivial Trunc_s). To keep life simple, we just
923	        -- force at least result_fmt.F+1 frac bits (even if this is sometimes one too many). The
924	        -- synthesis tool is likely to optimize this fine.
925	        constant mid_fmt_c      : FixFormat_t := (
926	            result_fmt.S,
927	            result_fmt.I,
928	            maximum(result_fmt.F+1, a_fmt.F)
929	        );
930	        constant in_offset_c    : natural := mid_fmt_c.F - a_fmt.F;
931	        constant out_offset_c   : natural := mid_fmt_c.F - result_fmt.F;
932	        constant half_c         : unsigned(cl_fix_width(mid_fmt_c)-1 downto 0) := get_half(mid_fmt_c, result_fmt);
933	        constant sign_c         : std_logic := cl_fix_sign(a_c, a_fmt);
934	        variable unit_v         : std_logic;
935	        variable mid_v          : unsigned(cl_fix_width(mid_fmt_c)-1 downto 0) := (others => '0');
936	        variable result_v       : std_logic_vector(cl_fix_width(result_fmt)-1 downto 0);
937	    begin
938	        -- Allow the designer to ignore the worst-case result format (with caution).
939	        if fmt_check then
940	            assert result_fmt = cl_fix_round_fmt(a_fmt, result_fmt.F, round)
941	                report "cl_fix_round: Invalid result format. Use cl_fix_round_fmt()." severity Failure;
942	        end if;
943	        
944	        -- Write the input value into mid_v with correct binary point alignment.
945	        mid_v := unsigned(convert(a_c, a_fmt, mid_fmt_c));
946	        
947	        -- To implement each rounding algorithm, we add an appropriate offset before truncating.
948	        if result_fmt.F < a_fmt.F then
949	            
950	            -- Get the least significant bit in the result format (for convergent rounding)
951	            unit_v := get_unit_bit(std_logic_vector(mid_v), mid_fmt_c, result_fmt);
952	            
953	            case round is
954	                when Trunc_s =>
955	                    null;  -- Crude truncation => no offset.
956	                when NonSymPos_s =>
957	                    mid_v := mid_v + half_c;
958	                when NonSymNeg_s =>
959	                    mid_v := mid_v + (half_c-1);
960	                when SymInf_s =>
961	                    mid_v := mid_v + half_c - ("" & sign_c);
962	                when SymZero_s =>
963	                    mid_v := mid_v + half_c - ("" & not sign_c);
964	                when ConvEven_s =>
965	                    mid_v := mid_v + half_c - ("" & not unit_v);
966	                when ConvOdd_s =>
967	                    mid_v := mid_v + half_c - ("" & unit_v);
968	                when others => report "Unrecognized rounding mode: " & to_string(round) severity Failure;
969	            end case;
970	        end if;
971	        
972	        -- Truncate (and force downto 0 by assigning to result_v before returning)
973	        result_v := std_logic_vector(mid_v(cl_fix_width(result_fmt)+out_offset_c-1 downto out_offset_c));
974	        
975	        return result_v;
976	    end;
977	    
978	    function cl_fix_saturate(
979	        a           : std_logic_vector;
980	        a_fmt       : FixFormat_t;
981	        result_fmt  : FixFormat_t;
982	        saturate    : FixSaturate_t := Warn_s
983	    ) return std_logic_vector is
984	        variable result_v   : std_logic_vector(cl_fix_width(result_fmt)-1 downto 0);
985	    begin
986	        assert result_fmt.F = a_fmt.F report "cl_fix_saturate: Number of frac bits cannot change." severity Failure;
987	        
988	        -- Saturation warning
989	        if saturate = Warn_s or saturate = SatWarn_s then
990	            assert cl_fix_in_range(a, a_fmt, result_fmt)
991	                report "cl_fix_saturate : Saturation warning!" severity Warning;
992	        end if;
993	        
994	        -- Write the input value into result_v with correct binary point alignment.
995	        result_v := convert(a, a_fmt, result_fmt);
996	        
997	        -- Saturate
998	        if saturate = Sat_s or saturate = SatWarn_s then
999	            if cl_fix_compare("<", a, a_fmt, cl_fix_min_value(result_fmt), result_fmt) then
1000	                result_v := cl_fix_min_value(result_fmt);
1001	            elsif cl_fix_compare(">", a, a_fmt, cl_fix_max_value(result_fmt), result_fmt) then
1002	                result_v := cl_fix_max_value(result_fmt);
1003	            end if;
1004	        end if;
1005	        
1006	        return result_v;
1007	    end;
1008	    
1009	    function cl_fix_resize(
1010	        a           : std_logic_vector;
1011	        a_fmt       : FixFormat_t;
1012	        result_fmt  : FixFormat_t;
1013	        round       : FixRound_t    := Trunc_s;
1014	        saturate    : FixSaturate_t := Warn_s
1015	    ) return std_logic_vector is
1016	        -- Round
1017	        constant rounded_fmt_c  : FixFormat_t := cl_fix_round_fmt(a_fmt, result_fmt.F, round);
1018	        constant rounded_c      : std_logic_vector := cl_fix_round(a, a_fmt, rounded_fmt_c, round);
1019	    begin
1020	        -- Saturate
1021	        return cl_fix_saturate(rounded_c, rounded_fmt_c, result_fmt, saturate);
1022	    end;
1023	    
1024	    function cl_fix_in_range(
1025	        a           : std_logic_vector;
1026	        a_fmt       : FixFormat_t;
1027	        result_fmt  : FixFormat_t;
1028	        round       : FixRound_t := Trunc_s
1029	    ) return boolean is
1030	        -- Note: If result_fmt.F /= a_fmt.F, then we need to know what rounding algorithm will be
1031	        --       used when reducing the LSBs.
1032	        constant rndFmt_c : FixFormat_t := cl_fix_round_fmt(a_fmt, result_fmt.F, round);
1033	        
1034	        -- Apply rounding
1035	        constant Rounded_c  : std_logic_vector := cl_fix_round(to01(a), a_fmt, rndFmt_c, round);
1036	    begin
1037	        return cl_fix_compare(">=", Rounded_c, rndFmt_c, cl_fix_min_value(result_fmt), result_fmt) and
1038	               cl_fix_compare("<=", Rounded_c, rndFmt_c, cl_fix_max_value(result_fmt), result_fmt);
1039	    end;
1040	    
1041	    function cl_fix_recommended_pipelining(
1042	        a_fmt       : FixFormat_t;
1043	        result_fmt  : FixFormat_t;
1044	        round       : FixRound_t;
1045	        fmt_check   : boolean := true
1046	    ) return natural is
1047	    begin
1048	        -- Allow the designer to ignore the worst-case result format (with caution).
1049	        if fmt_check then
1050	            assert result_fmt = cl_fix_round_fmt(a_fmt, result_fmt.F, round)
1051	                report "cl_fix_recommended_pipelining: Invalid result format. Use cl_fix_round_fmt()." severity Failure;
1052	        end if;
1053	        
1054	        -- Registering is not needed if zero logic is used. This happens in two cases:
1055	        -- (1) During truncation.
1056	        if round = Trunc_s then
1057	            return 0;
1058	        else
1059	            -- If a new rounding mode is defined, then appropriate behavior must be implemented.
1060	            assert round = NonSymPos_s or round = NonSymNeg_s or round = SymInf_s or round = SymZero_s or round = ConvEven_s or round = ConvOdd_s
1061	                report "cl_fix_recommended_pipelining: Unhandled rounding mode."
1062	                severity Failure;
1063	        end if;
1064	        -- (2) If the number of fractional bits isn't being decreased.
1065	        if result_fmt.F >= a_fmt.F then
1066	            return 0;
1067	        end if;
1068	        return 1;
1069	    end;
1070	    
1071	    function cl_fix_recommended_pipelining(
1072	        a_fmt       : FixFormat_t;
1073	        result_fmt  : FixFormat_t;
1074	        saturate    : FixSaturate_t
1075	    ) return natural is
1076	    begin
1077	        assert result_fmt.F = a_fmt.F
1078	            report "cl_fix_recommended_pipelining: Number of frac bits cannot change during saturation."
1079	            severity Failure;
1080	        
1081	        -- Registering is not needed if zero logic is used. This happens in two cases:
1082	        -- (1) During wrapping.
1083	        if saturate = None_s or saturate = Warn_s then
1084	            return 0;
1085	        else
1086	            -- If a new saturation mode is defined, then appropriate behavior must be implemented.
1087	            assert saturate = Sat_s or saturate = SatWarn_s
1088	                report "cl_fix_recommended_pipelining: Unhandled saturation mode."
1089	                severity Failure;
1090	        end if;
1091	        -- (2) If the number of integer bits is not being decreased, and the number of sign bits is
1092	        --     not being changed.
1093	        if result_fmt.I >= a_fmt.I and result_fmt.S = a_fmt.S then
1094	            return 0;
1095	        end if;
1096	        return 1;
1097	    end;
1098	    
1099	    function cl_fix_recommended_pipelining(
1100	        a_fmt       : FixFormat_t;
1101	        result_fmt  : FixFormat_t;
1102	        round       : FixRound_t;
1103	        saturate    : FixSaturate_t
1104	    ) return natural is
1105	        constant round_fmt_c    : FixFormat_t := cl_fix_round_fmt(a_fmt, result_fmt.F, round);
1106	    begin
1107	        return cl_fix_recommended_pipelining(a_fmt, round_fmt_c, round)
1108	             + cl_fix_recommended_pipelining(round_fmt_c, result_fmt, saturate);
1109	    end;
1110	    
1111	    function cl_fix_abs(
1112	        a           : std_logic_vector;
1113	        a_fmt       : FixFormat_t;
1114	        result_fmt  : FixFormat_t := NullFixFormat_c;
1115	        round       : FixRound_t := Trunc_s;
1116	        saturate    : FixSaturate_t := Warn_s
1117	    ) return std_logic_vector is
1118	        constant mid_fmt_c  : FixFormat_t := cl_fix_abs_fmt(a_fmt);
1119	        constant r_fmt_c    : FixFormat_t := choose(result_fmt = NullFixFormat_c, mid_fmt_c, result_fmt);
1120	        variable mid_v      : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1121	    begin
1122	        if cl_fix_sign(a, a_fmt) = '1' then
1123	            mid_v := cl_fix_neg(a, a_fmt, mid_fmt_c);
1124	        else
1125	            mid_v := convert(a, a_fmt, mid_fmt_c);
1126	        end if;
1127	        return cl_fix_resize(mid_v, mid_fmt_c, r_fmt_c, round, saturate);
1128	    end;
1129	    
1130	    function cl_fix_neg(
1131	        a           : std_logic_vector;
1132	        a_fmt       : FixFormat_t;
1133	        result_fmt  : FixFormat_t := NullFixFormat_c;
1134	        round       : FixRound_t := Trunc_s;
1135	        saturate    : FixSaturate_t := Warn_s
1136	    ) return std_logic_vector is
1137	        constant mid_fmt_c  : FixFormat_t := cl_fix_neg_fmt(a_fmt);
1138	        constant r_fmt_c    : FixFormat_t := choose(result_fmt = NullFixFormat_c, mid_fmt_c, result_fmt);
1139	        variable a_v        : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1140	        variable mid_v      : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1141	    begin
1142	        a_v := convert(a, a_fmt, mid_fmt_c);
1143	        mid_v := std_logic_vector(-signed(a_v));
1144	        return cl_fix_resize(mid_v, mid_fmt_c, r_fmt_c, round, saturate);
1145	    end;
1146	    
1147	    function cl_fix_add(
1148	        a           : std_logic_vector;
1149	        a_fmt       : FixFormat_t;
1150	        b           : std_logic_vector;
1151	        b_fmt       : FixFormat_t;
1152	        result_fmt  : FixFormat_t := NullFixFormat_c;
1153	        round       : FixRound_t := Trunc_s;
1154	        saturate    : FixSaturate_t := Warn_s
1155	    ) return std_logic_vector is
1156	        constant mid_fmt_c  : FixFormat_t := cl_fix_add_fmt(a_fmt, b_fmt);
1157	        constant r_fmt_c    : FixFormat_t := choose(result_fmt = NullFixFormat_c, mid_fmt_c, result_fmt);
1158	        variable a_v        : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1159	        variable b_v        : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1160	        variable mid_v      : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1161	    begin
1162	        a_v := convert(a, a_fmt, mid_fmt_c);
1163	        b_v := convert(b, b_fmt, mid_fmt_c);
1164	        -- Signed/unsigned addition/subtraction are identical when using two's complement.
1165	        -- However, a long-standing Vivado bug causes incorrect post-synthesis behavior in DSP
1166	        -- slices (pre-add or post-add) if numeric_std.unsigned is used. There are no known issues
1167	        -- for numeric_std.signed, so we always use that.
1168	        mid_v := std_logic_vector(signed(a_v) + signed(b_v));
1169	        return cl_fix_resize(mid_v, mid_fmt_c, r_fmt_c, round, saturate);
1170	    end;
1171	    
1172	    function cl_fix_sub(
1173	        a           : std_logic_vector;
1174	        a_fmt       : FixFormat_t;
1175	        b           : std_logic_vector;
1176	        b_fmt       : FixFormat_t;
1177	        result_fmt  : FixFormat_t := NullFixFormat_c;
1178	        round       : FixRound_t := Trunc_s;
1179	        saturate    : FixSaturate_t := Warn_s
1180	    ) return std_logic_vector is
1181	        constant mid_fmt_c  : FixFormat_t := cl_fix_sub_fmt(a_fmt, b_fmt);
1182	        constant r_fmt_c    : FixFormat_t := choose(result_fmt = NullFixFormat_c, mid_fmt_c, result_fmt);
1183	        variable a_v        : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1184	        variable b_v        : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1185	        variable mid_v      : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1186	    begin
1187	        a_v := convert(a, a_fmt, mid_fmt_c);
1188	        b_v := convert(b, b_fmt, mid_fmt_c);
1189	        -- Signed/unsigned addition/subtraction are identical when using two's complement.
1190	        -- However, a long-standing Vivado bug causes incorrect post-synthesis behavior in DSP
1191	        -- slices (pre-add or post-add) if numeric_std.unsigned is used. There are no known issues
1192	        -- for numeric_std.signed, so we always use that.
1193	        mid_v := std_logic_vector(signed(a_v) - signed(b_v));
1194	        return cl_fix_resize(mid_v, mid_fmt_c, r_fmt_c, round, saturate);
1195	    end;
1196	    
1197	    function cl_fix_addsub(
1198	        a           : std_logic_vector;
1199	        a_fmt       : FixFormat_t;
1200	        b           : std_logic_vector;
1201	        b_fmt       : FixFormat_t;
1202	        add         : std_logic;
1203	        result_fmt  : FixFormat_t := NullFixFormat_c;
1204	        round       : FixRound_t := Trunc_s;
1205	        saturate    : FixSaturate_t := Warn_s
1206	    ) return std_logic_vector is
1207	    begin
1208	        if to01(add) = '1' then
1209	            return cl_fix_add(a, a_fmt, b, b_fmt, result_fmt, round, saturate);
1210	        end if;
1211	        return cl_fix_sub(a, a_fmt, b, b_fmt, result_fmt, round, saturate);
1212	    end;
1213	    
1214	    function cl_fix_mult(
1215	        a           : std_logic_vector;
1216	        a_fmt       : FixFormat_t;
1217	        b           : std_logic_vector;
1218	        b_fmt       : FixFormat_t;
1219	        result_fmt  : FixFormat_t := NullFixFormat_c;
1220	        round       : FixRound_t := Trunc_s;
1221	        saturate    : FixSaturate_t := Warn_s
1222	    ) return std_logic_vector is
1223	        -- Force downto 0
1224	        constant a_c            : std_logic_vector(cl_fix_width(a_fmt)-1 downto 0) := a;
1225	        constant b_c            : std_logic_vector(cl_fix_width(b_fmt)-1 downto 0) := b;
1226	        
1227	        -- VHDL doesn't define a * operator for mixed signed*unsigned or unsigned*signed.
1228	        -- Just inside cl_fix_mult, it is safe to define them for local use.
1229	        function "*"(x : signed; y : unsigned) return signed is
1230	        begin
1231	            return x * ('0' & signed(y));
1232	        end function;
1233	        
1234	        function "*"(x : unsigned; y : signed) return signed is
1235	        begin
1236	            return y * x;
1237	        end function;
1238	        
1239	        constant mid_fmt_c      : FixFormat_t := cl_fix_mult_fmt(a_fmt, b_fmt);
1240	        constant r_fmt_c        : FixFormat_t := choose(result_fmt = NullFixFormat_c, mid_fmt_c, result_fmt);
1241	        constant mid_width_c    : positive := cl_fix_width(mid_fmt_c);
1242	        variable mid_v          : std_logic_vector(mid_width_c-1 downto 0);
1243	    begin
1244	        if a_fmt.S = 0 and b_fmt.S = 0 then
1245	            mid_v := std_logic_vector(resize(unsigned(a_c) * unsigned(b_c), mid_width_c));
1246	        elsif a_fmt.S = 0 and b_fmt.S = 1 then
1247	            mid_v := std_logic_vector(resize_sensible(unsigned(a_c) * signed(b_c), mid_width_c));
1248	        elsif a_fmt.S = 1 and b_fmt.S = 0 then
1249	            mid_v := std_logic_vector(resize_sensible(signed(a_c) * unsigned(b_c), mid_width_c));
1250	        else
1251	            mid_v := std_logic_vector(resize_sensible(signed(a_c) * signed(b_c), mid_width_c));
1252	        end if;
1253	        
1254	        return cl_fix_resize(mid_v, mid_fmt_c, r_fmt_c, round, saturate);
1255	    end;
1256	    
1257	    function cl_fix_shift(
1258	        a           : std_logic_vector;
1259	        a_fmt       : FixFormat_t;
1260	        shift       : integer;
1261	        result_fmt  : FixFormat_t;
1262	        round       : FixRound_t := Trunc_s;
1263	        saturate    : FixSaturate_t := Warn_s
1264	    ) return std_logic_vector is
1265	        -- Implicitly shift by resizing to a dummy format, then reinterpreting as result_fmt.
1266	        constant dummy_fmt_c  : FixFormat_t := (result_fmt.S, result_fmt.I - shift, result_fmt.F + shift);
1267	    begin
1268	        -- Note: This function performs a lossless shift (equivalent to *2.0**shift), then resizes
1269	        --       to the output format. The initial shift does NOT truncate any bits.
1270	        -- Note: "shift" direction is left. (So shift<0 shifts right).
1271	        return cl_fix_resize(a, a_fmt, dummy_fmt_c, round, saturate);
1272	    end;
1273	    
1274	    function cl_fix_compare(
1275	        comparison  : string;
1276	        a           : std_logic_vector;
1277	        aFmt        : FixFormat_t;
1278	        b           : std_logic_vector;
1279	        bFmt        : FixFormat_t
1280	    ) return boolean is
1281	        constant mid_fmt_c  : FixFormat_t := union(aFmt, bFmt);
1282	        variable a_v        : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1283	        variable b_v        : std_logic_vector(cl_fix_width(mid_fmt_c)-1 downto 0);
1284	    begin
1285	        -- Convert to same type
1286	        a_v := convert(a, aFmt, mid_fmt_c);
1287	        b_v := convert(b, bFmt, mid_fmt_c);
1288	        
1289	        -- Compare
1290	        if mid_fmt_c.S = 1 then
1291	            if    comparison = "="  then return signed(a_v) =  signed(b_v);
1292	            elsif comparison = "!=" then return signed(a_v) /= signed(b_v);
1293	            elsif comparison = "<"  then return signed(a_v) <  signed(b_v);
1294	            elsif comparison = ">"  then return signed(a_v) >  signed(b_v);
1295	            elsif comparison = "<=" then return signed(a_v) <= signed(b_v);
1296	            elsif comparison = ">=" then return signed(a_v) >= signed(b_v);
1297	            else
1298	                report "cl_fix_compare: Unrecognized comparison type: " & comparison severity Failure;
1299	                return false;
1300	            end if;
1301	        else
1302	            if    comparison = "="  then return unsigned(a_v) =  unsigned(b_v);
1303	            elsif comparison = "!=" then return unsigned(a_v) /= unsigned(b_v);
1304	            elsif comparison = "<"  then return unsigned(a_v) <  unsigned(b_v);
1305	            elsif comparison = ">"  then return unsigned(a_v) >  unsigned(b_v);
1306	            elsif comparison = "<=" then return unsigned(a_v) <= unsigned(b_v);
1307	            elsif comparison = ">=" then return unsigned(a_v) >= unsigned(b_v);
1308	            else
1309	                report "cl_fix_compare: Unrecognized comparison type: " & comparison severity Failure;
1310	                return false;
1311	            end if;
1312	        end if;
1313	    end function;
1314	    
1315	    function cl_fix_sign(a : std_logic_vector; aFmt : FixFormat_t) return std_logic is
1316	        -- Force downto 0
1317	        constant a_c    : std_logic_vector(cl_fix_width(aFmt)-1 downto 0) := a;
1318	    begin
1319	        if aFmt.S = 0 or cl_fix_width(aFmt) = 0 then
1320	            return '0';
1321	        end if;
1322	        return a_c(a_c'high);
1323	    end function;
1324	end;
