106	        constant Amin       : integer := cl_fix_to_integer(cl_fix_min_value(a_fmt_c(i)), a_fmt_c(i));
107	        constant Amax       : integer := cl_fix_to_integer(cl_fix_max_value(a_fmt_c(i)), a_fmt_c(i));
108	        
109	        signal rst          : std_logic;
110	        
111	        signal in_valid     : std_logic;
112	        signal in_meta      : std_logic_vector(meta_width_g-1 downto 0);
113	        signal in_data      : std_logic_vector(cl_fix_width(a_fmt_c(i))-1 downto 0);
