227	-- Package Body
228	---------------------------------------------------------------------------------------------------
229	package body en_cl_fix_fileio_pkg is
230	    
231	    -----------------------------------------------------------------------------------------------
232	    -- Private Functions
233	    -----------------------------------------------------------------------------------------------
234	    
235	    -- Helper function to determine Signedness_t from FixFormat_t
236	    function cl_fix_to_signedness(constant Fmt : in FixFormat_t) return Signedness_t is
237	    begin
238	        if Fmt.S = 1 then
239	            return Signed_s;
240	        else
241	            return Unsigned_s;
242	        end if;
243	    end function;
244	    
245	    -----------------------------------------------------------------------------------------------
246	    -- Read Access
247	    -----------------------------------------------------------------------------------------------
248	    
249	    -----------------------------------------
250	    -- Read EN_CL_FIX Data From Text Files --
251	    -----------------------------------------
252	    
253	    -- Parse ASCII text line as a single fixed-point value
254	    procedure cl_fix_read(
255	        variable L          : inout line;
256	        variable Data       : out   ieee.std_logic_1164.std_logic_vector;
257	        constant Fmt        : in    FixFormat_t;
258	        constant TextMode   : in    text_data_mode_t := ascii_dec
259	    ) is
260	    begin
261	        read(L, Data, cl_fix_to_signedness(Fmt), TextMode);
262	    end procedure;
263	    
264	    -- Read a single fixed-point value from a single-column ASCII text file
265	    impure function cl_fix_read(
266	        file     F          : text;
267	        constant Fmt        : FixFormat_t;
268	        constant TextMode   : text_data_mode_t := ascii_dec;
269	        constant SkipBefore : natural := 0;
270	        constant CloseAfter : boolean := false
271	    ) return std_logic_vector is
272	        variable Line_v     : line;
273	        variable Value_v    : std_logic_vector(cl_fix_width(Fmt)-1 downto 0);
274	    begin
275	        skip_lines(F, SkipBefore);
276	        readline(F, Line_v);
277	        cl_fix_read(Line_v, Value_v, Fmt, TextMode);
278	        deallocate(Line_v);
279	        if CloseAfter then
280	            file_close(F);
281	        end if;
282	        return Value_v;
283	    end function;
284	    
285	    -- Read a whole text file containing fixed-point data
286	    impure function cl_fix_read_file(
287	        constant Filename   : in string;
288	        constant Fmt        : in FixFormat_t;
289	        constant TextMode   : in text_data_mode_t := ascii_dec;
290	        constant SkipLines  : in natural := 1
291	    ) return SlvArray_t is
292	    begin
293	        return read_file(Filename, cl_fix_width(Fmt), cl_fix_to_signedness(Fmt), TextMode, SkipLines);
294	    end function;
295	    
296	    ------------------------------------------------
297	    -- Read EN_CL_FIX FixFormat_t From Text Files --
298	    ------------------------------------------------
299	    
300	    -- Parse ASCII text line as a single FixFormat_t
301	    procedure cl_fix_read_format(
302	        variable L          : inout line;
303	        variable Fmt        : out   FixFormat_t
304	    ) is
305	    begin
306	        Fmt := cl_fix_format_from_string(L.all);
307	        L := new string'("");
308	    end procedure;
309	    
310	    -- Read a single FixFormat_t from a single-column ASCII text file
311	    impure function cl_fix_read_format(
312	        file F              : text;
313	        constant SkipBefore : natural := 0;
314	        constant CloseAfter : boolean := false
315	    ) return FixFormat_t is
316	        variable Line_v     : line;
317	        variable Fmt_v      : FixFormat_t;
318	    begin
319	        skip_lines(F, SkipBefore);
320	        readline(F, Line_v);
321	        cl_fix_read_format(Line_v, Fmt_v);
322	        deallocate(Line_v);
323	        if CloseAfter then
324	            file_close(F);
325	        end if;
326	        return Fmt_v;
327	    end function;
328	    
329	    -- Read a whole text file containing a single column of FixFormat_t strings
330	    impure function cl_fix_read_format_file(
331	        constant Filename   : in string;
332	        constant SkipLines  : in natural := 1
333	    ) return FixFormatArray_t is
334	        constant FormatCount_c  : natural := get_file_size_lines(Filename) - SkipLines;
335	        file     F              : text;
336	        variable Line_v         : line;
337	        variable Formats_v      : FixFormatArray_t(0 to FormatCount_c-1);
338	    begin
339	        file_open(F, Filename, read_mode);
340	        -- Discard header lines
341	        skip_lines(F, SkipLines);
342	        -- Read formats
343	        for i in 0 to FormatCount_c-1 loop
344	            Formats_v(i) := cl_fix_read_format(F);
345	        end loop;
346	        deallocate(Line_v);
347	        file_close(F);
348	        return Formats_v;
349	    end function;
350	    
351	    -----------------------------------------------------------------------------------------------
352	    -- Write Access
353	    -----------------------------------------------------------------------------------------------
354	    
355	    ----------------------------------------
356	    -- Write EN_CL_FIX Data To Text Files --
357	    ----------------------------------------
358	    
359	    -- Write a single fixed-point value to a text line
360	    procedure cl_fix_write(
361	        variable L          : inout line;
362	        constant Data       : in    std_logic_vector;
363	        constant Fmt        : in    FixFormat_t;
364	        constant TextMode   : in    text_data_mode_t := ascii_dec
365	    ) is
366	    begin
367	        write(L, Data, cl_fix_to_signedness(Fmt), TextMode);
368	    end procedure;
369	    
370	    -- Write a single fixed-point value to a text file
371	    procedure cl_fix_write(
372	        file     F          : text;
373	        constant Data       : in    std_logic_vector;
374	        constant Fmt        : in    FixFormat_t;
375	        constant TextMode   : in    text_data_mode_t := ascii_dec
376	    ) is
377	    begin
378	        write(F, Data, cl_fix_to_signedness(Fmt), TextMode);
379	    end procedure;
380	    
381	    -- Write a whole text file of fixed-point data
382	    procedure cl_fix_write_file(
383	        constant Filename   : in  string;
384	        constant Data       : in  SlvArray_t;
385	        constant Fmt        : in  FixFormat_t;
386	        constant TextMode   : in  text_data_mode_t := ascii_dec;
387	        constant Header     : in  string := ""
388	    ) is
389	    begin
390	        write_file(Filename, Data, cl_fix_to_signedness(Fmt), TextMode, Header);
391	    end procedure;
392	    
393	    -----------------------------------------------
394	    -- Write EN_CL_FIX FixFormat_t To Text Files --
395	    -----------------------------------------------
396	    
397	    -- Write a single FixFormat_t to a text line
398	    procedure cl_fix_write_format(
399	        variable L          : inout line;
400	        constant Fmt        : in FixFormat_t
401	    ) is
402	    begin
403	        write(L, to_string(Fmt));
404	    end procedure;
405	    
406	    -- Write a single FixFormat_t to a text file
407	    procedure cl_fix_write_format(
408	        file F          : text;
409	        constant Fmt    : in FixFormat_t
410	    ) is
411	        variable Line_v     : line;
412	    begin
413	        cl_fix_write_format(Line_v, Fmt);
414	        writeline(F, Line_v);
415	        deallocate(Line_v);
416	    end procedure;
417	    
418	    -- Write an array of FixFormat_t strings to a text file
419	    procedure cl_fix_write_format_file(
420	        constant Filename   : in string;
421	        constant Formats    : in FixFormatArray_t
422	    ) is
423	        file F          : text;
424	    begin
425	        file_open(F, Filename, write_mode);
426	        for i in Formats'range loop
427	            cl_fix_write_format(F, Formats(i));
428	        end loop;
429	        file_close(F);
430	    end procedure;
431	    
432	end package body;
